import{_ as p,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"战技","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/6.一次性血统/载魂者/战技.md","filePath":"4.资源分区/1.血统与训练/6.一次性血统/载魂者/战技.md"}'),s={name:"4.资源分区/1.血统与训练/6.一次性血统/载魂者/战技.md"};function o(d,b,l,i,_,c){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"战技",tabindex:"-1"},[t("战技 "),r("a",{class:"header-anchor",href:"#战技","aria-label":'Permalink to "战技"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌039")])])],-1),n('<h1 id="战技-1" tabindex="-1">战技 <a class="header-anchor" href="#战技-1" aria-label="Permalink to &quot;战技&quot;">​</a></h1><p>【战技】<br> 每个战技皆有自身的位片组合需求，你需要具有组合需求中的灵魂位片并花费1个D级别支线才能获得，获得战技如同习得一个D级别技艺，并在获得后永久性失去战技组合所需的位片。</p><p>初始战技：<br> 热能+打击＝火焰冲击<br> 热能+斩击＝火焰利刃<br> 热能+刺击＝火焰针刺<br> 热能+射击＝燃烧狙击<br> 热能+冷静＝红炎（未完成）<br> 热能+蓄力＝愤怒火焰（未完成）</p><p>疾风+打击＝暴风冲击<br> 疾风+斩击＝暴风利刃<br> 疾风+刺击＝暴风针刺<br> 疾风+射击＝暴风狙击<br> 疾风+灵敏＝幻象（未完成）<br> 疾风+蓄力＝狂风（未完成）</p><p>冰冻+打击＝冰霜砸击<br> 冰冻+斩击＝冰锥利刃<br> 冰冻+刺击＝寒冰针刺<br> 冰冻+射击＝冻结狙击<br> 冰冻+蓄力＝冰冻连锁（未完成）<br> 冰冻+防守＝冰冷护体（未完成）</p><p>电击+打击＝雷霆砸击<br> 电击+斩击＝电光利刃<br> 电击+刺击＝电击针刺<br> 电击+射击＝雷霆狙击<br> 电击+瞄准＝瞄准波导（未完成）<br> 电击+蓄力＝电光（未完成）</p><p>岩石+打击＝坚石撞击<br> 岩石+斩击＝地壑砸击<br> 岩石+刺击＝俯冲震击<br> 岩石+射击＝岩石连锁<br> 岩石+蓄力＝埋葬（未完成）<br> 岩石+防守＝防护墙（未完成）</p><p>热能+疾风＝热能波动（未完成）<br> 疾风+冰冻＝冰冷波动（未完成）<br> 电击+冰冻＝电击波动（未完成）<br> 岩石+疾风＝岩石波动（未完成）<br> 热能+冰冻＝蒸汽爆裂（未完成）</p><p>热能+电击＝电离激光（未完成）<br> 电击+岩石＝雷霆弹（未完成）<br> 冰冻+岩石＝冰霜之箭（未完成）<br> 冷静+冰冻＝冷静之雨（未完成）<br> 热能+岩石＝火球（未完成）</p><p>打击+蓄力＝无间冲击（未完成）<br> 打击+瞄准＝猛攻旋踢（未完成）<br> 打击+防御＝屈服锁技（未完成）<br> 打击+刺击＝标枪（未完成）</p><p>刺击+灵敏＝擎天俯冲（未完成）<br> 刺击+蓄力＝贯穿击（未完成）</p><p>射击+冷静＝连射（未完成）<br> 射击+瞄准＝惊魂射击（未完成）</p><p>治愈+蓄力＝特级治愈（未完成）</p><p>进阶战技：<br> 电击+打击+蓄力＝霹雳踢击（未完成）<br> 打击+蓄力+瞄准＝升龙闪（未完成）<br> 打击+蓄力+冷静＝流星飞腿（未完成）<br> 刺击+打击+瞄准＝锚定标枪（未完成）<br> 刺击+灵敏+瞄准＝绝命桩刺（未完成）<br> 打击+灵敏+蓄力＝修罗厮杀（未完成）<br> 射击+打击+灵敏＝暴乱射击（未完成）<br> 打击+蓄力+岩石＝地球震击（未完成）<br> 射击+电击+打击＝雷霆轮射（未完成）<br> 斩击+冰冻+打击＝冰结旋斩（未完成）<br> 斩击+热能+打击＝火焰旋斩（未完成）<br> 刺击+疾风+打击＝暴风旋枪（未完成）<br> 打击+岩石+瞄准＝百臂咆哮（未完成）</p><p>火焰冲击<br> 动作：标准动作+花招动作<br> 消耗：-<br> 持续：立即<br> 描述：灼热气浪，爆炎一击。<br> 效果：你进行一次普通近战攻击，本次攻击伤害类型转为火焰能量伤害，附带等同【决心/3（向下取整）】点威猛与1点不可豁免的燃烧不良点数。</p><p>火焰利刃<br> 动作：标准动作<br> 消耗：-<br> 持续：立即<br> 描述：炽热斩击，火光摇曳。<br> 效果：你进行一次普通近战攻击，本次攻击伤害类型转为火焰能量伤害，附带等同【力量/3（向上取整）】点破甲与【能量武器】特性。</p><p>火焰针刺<br> 动作：标准动作+花招动作<br> 消耗：-<br> 持续：立即<br> 描述：凝火成针，内爆灼烧。<br> 效果：你进行一次普通近战攻击，本次攻击伤害类型转为火焰能量伤害，附带等同【敏捷/3（向上取整）】点高速，并额外造成【传奇敏捷/2（向上取整）】点韧性伤害。</p><p>燃烧狙击<br> 动作：标准动作<br> 消耗：-<br> 持续：立即<br> 描述：贯射炎弹，引发小范围爆燃。<br> 效果：进行一次普通射击攻击，本次攻击伤害类型转为火焰能量伤害，附带等同【敏捷/3（向上取整）】点高速，同时对攻击落点5米内的所有单位造成伤害。</p><p>暴风冲击<br> 动作：标准动作+迅捷动作<br> 消耗：-<br> 持续：立即<br> 描述：压缩气爆，位于中距离轰出风压。<br> 效果：你进行一次普通近战攻击，本次攻击伤害类型转为音波（振动），附带内在最高支线等级*1点【威猛】与【余波】特性，同时攻击触及距离提升【传奇敏捷*1.5（向上取整）】米。</p><p>暴风利刃<br> 动作：标准动作+迅捷动作<br> 消耗：-<br> 持续：立即<br> 描述：音刃裂空，飓风随行。<br> 效果：你进行一次普通近战攻击，本次攻击伤害类型转为音波（振动），附带【敏捷/3（向上取整）】点破甲，本次攻击可对前方5米内所有单位同时造成伤害，并额外造成1点严重伤害。</p><p>暴风针刺<br> 动作：标准动作<br> 消耗：-<br> 持续：立即<br> 描述：将气旋凝于刃尖，进行贯穿刺击。<br> 效果：你进行一次普通近战攻击，本次攻击伤害类型转为音波（振动），附带【敏捷/3（向上取整）】点高速，具有【贯穿】特性，并在命中后降低目标1点任意防御附加成功数（持续一轮）。</p><p>暴风狙击<br> 动作：标准动作+花招动作<br> 消耗：-<br> 持续：立即<br> 描述：风压修正弹道，子弹出膛即达。<br> 效果：进行一次普通射击攻击，本次攻击伤害类型转为音波（振动）伤害，附带等同【敏捷/2（向上取整）】点高速，并将射程+1倍处理（步枪或狙击枪则改为增加内在最高支线等级*10米射程），在处理本次攻击承受的环境减值时，将减值抵消3点。</p><p>冰霜砸击<br> 动作：整轮动作+花招动作<br> 消耗：-<br> 持续：见下<br> 描述：裹挟极寒，轰击凝霜<br> 效果：进行一次普通近战攻击，本次攻击伤害类型转为寒冷伤害，附带等同内在最高支线等级*1点威猛，攻击命中的位置将在下一轮开始时生成半径等同你触及距离*1米的冰霜区域（视为D级环境来源的困难地形），位于冰霜区内的单位将承受D级环境来源的【潮湿】效果，冰霜区域仅持续存在一轮。</p><p>冰锥利刃<br> 动作：标准动作??<br> 消耗：-<br> 持续：立即??<br> 描述：覆刃横斩，寒潮随形。<br> 效果：进行一次普通近战攻击，本次攻击伤害类型转为寒冷伤害，附带等同【沉着/3】点破甲，并在攻击命中后造成1点不可豁免的冻结不良点数。</p><p>寒冰针刺<br> 动作：标准动作<br> 消耗：-<br> 持续：立即??<br> 描述：冻气刺击，凝血成冰。<br> 效果：进行一次普通近战攻击，本次攻击伤害类型转为寒冷伤害，附带等同【沉着/3】点高速，并在攻击命中后造成1点不可豁免的冻结不良点数。</p><p>冻结狙击<br> 动作：标准动作+花招动作<br> 消耗：-<br> 持续：见下<br> 描述：冰弹贯空，霜迹留痕。<br> 效果：进行一次普通射击攻击，本次攻击伤害类型转为寒冷伤害，附带等同【沉着/3】+1点破甲，并在攻击命中后使目标的基础移动速度降低等同你【沉着*2】米，持续一轮。</p><p>雷霆砸击<br> 动作：标准动作+花招动作<br> 消耗：-<br> 持续：立即<br> 描述：迸发雷霆，震狱破邪<br> 效果：进行一次普通近战攻击，本次攻击伤害类型转为雷电能量，附带1点不可豁免的麻痹不良点数，并对触及距离内的所有敌对单位造成伤害。</p><p>电光利刃<br> 动作：标准动作+花招动作<br> 消耗：-<br> 持续：立即<br> 描述：电弧缠绕，刃跃雷光。<br> 效果：进行一次普通近战攻击，本次攻击伤害类型转为雷电能量，附带【力量/3】点破甲与1个额外附加成功数，并可以额外攻击等同【传奇力量】+1个目标，但无法重复攻击同一目标。</p><p>电击针刺<br> 动作：标准动作+花招动作<br> 消耗：-<br> 持续：立即<br> 描述：电压集中，破防贯体。<br> 效果：进行一次普通近战攻击，本次攻击伤害类型转为雷电能量，附带【力量/3】点熔毁，并且你可以在本次攻击检定上承受2点器械减值从而无视目标至多不超过这些器械减值*1点伤害吸收/减免类能力。</p><p>雷霆狙击<br> 动作：标准动作+迅捷动作<br> 消耗：-<br> 持续：立即<br> 描述：雷矢贯空，强光致盲。<br> 效果：进行一次普通射击攻击，本次攻击伤害类型转为雷电能量，对攻击落点5米内的所有敌对单位造成伤害，并附带等同伤害出目*1点目眩不良点数（视为D级环境来源），无论豁免成功数如何，至少会造成1点目眩不良点数，除非目标有着能够降低承受异常点数的能力。</p><p>坚石撞击<br> 动作：标准动作+花招动作<br> 消耗：-<br> 持续：立即<br> 描述：重轰地表，岩突石崩。<br> 效果：你进行一次普通近战攻击，本次攻击伤害类型转为力场伤害，本次攻击同时对触及距离内所有敌对单位造成伤害，附带等同内在最高支线等级*1点【威猛】，范围内所有敌对需进行反射豁免对抗伤害出目，失败则陷入【伏地】状态。</p><p>地壑砸击<br> 动作：标准动作+花招动作<br> 消耗：-<br> 持续：见下<br> 描述：劈裂大地，沟壑纵横。<br> 效果：你进行一次普通近战攻击，本次攻击伤害类型转为力场伤害，攻击同时对前方扇形10米距离内所有敌对单位造成伤害，附带等同内在最高支线等级*1点【破甲】，并在下一轮在前方切裂出长宽皆为10米，深1米的沟壑（沟壑视为D级环境来源的困难地形），一轮后沟壑将自然消除。</p><p>俯冲震击<br> 动作：标准动作+花招动作<br> 消耗：-<br> 持续：立即<br> 描述：贯地突刺，震波扩散。<br> 效果：你进行一次普通近战攻击，本次攻击伤害类型转为力场伤害，并附带【力量/3】点高速，同时对前方扇形10米距离内所有敌对单位造成伤害。</p><p>岩石连锁<br> 动作：标准动作+迅捷动作<br> 消耗：-<br> 持续：立即<br> 描述：投掷岩块，弹跳连环<br> 效果：你进行一次普通投掷或者射击攻击，本次攻击伤害类型转为力场伤害，并附带【力量/3】点高速，具有【余波】特性，并可以额外攻击3个目标，无法选择同一目标。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',36)])])}const m=p(s,[["render",o]]);export{f as __pageData,m as default};
